import hashlib

def hash_message(message):
    if message == "":
        return None

    def recursive_hash(s):
        if len(s) == 0:
            return ""
        return hashlib.sha256(s[0].encode()).hexdigest() + recursive_hash(s[1:])

    return recursive_hash(message)
